mapper.select:


     and tr.account_id = #{accountId}
     and tr.elder_id = #{elderId}
     and tr.institution_id = #{institutionId}
     and tr.transaction_no like concat('%', #{transactionNo}, '%')
     and tr.transaction_type = #{transactionType}
     and tr.business_type = #{businessType}
     and tr.amount = #{amount}
     and tr.counterparty like concat('%', #{counterparty}, '%')
     and tr.operator like concat('%', #{operator}, '%')

        and date_format(tr.transaction_date,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


        and date_format(tr.transaction_date,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


order by tr.transaction_date desc

select
    transaction_type,
    count(*) as transaction_count,
    sum(amount) as total_amount,
    sum(case when transaction_type = '1' then amount else 0 end) as income_amount,
    sum(case when transaction_type = '2' then amount else 0 end) as expense_amount
from transaction_record
where account_id = #{accountId}

    and business_type = #{businessType}


    and transaction_date >= #{startDate}


    and transaction_date <= #{endDate}

group by transaction_type


where account_id = #{accountId}
order by transaction_date desc
limit #{limit}

select
    transaction_type,
    sum(amount) as totalAmount,
    count(*) as count
from transaction_record
where institution_id = #{institutionId}

    and date_format(transaction_date, '%Y-%m-%d') >= #{startDate}


    and date_format(transaction_date, '%Y-%m-%d') <= #{endDate}

group by transaction_type

select
    business_type,
    sum(amount) as totalAmount,
    count(*) as count
from transaction_record
where institution_id = #{institutionId}

    and date_format(transaction_date, '%Y-%m-%d') >= #{startDate}


    and date_format(transaction_date, '%Y-%m-%d') <= #{endDate}

group by business_type

